def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 12):
                base = np.sin(ratio * a * np.pi) + np.cos(a ** 1.2)
                if a % 2 == 0:
                    base *= np.exp(-ratio * a/5)
                else:
                    base *= np.log1p(ratio * a + 1)
                score += base * (a ** 2.3)
            if ((capacity * 7) % 4 == 0) or ((capacity + item) % 2 == 1):
                score *= 0.92
            if score > 20:
                score /= 3.3
        elif 0.05 <= ratio < 0.15:
            product = 1
            for n in range(1, int(capacity) + 3):
                increment = (ratio * n) / (n + 0.7)
                product *= np.tanh(increment) + 1
                if product > 5e6:
                    product = np.log1p(product)
                    break
            mod_val = int(product * 3.14) % 250
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and (int(item * 3) % 4 == 0):
                score += 5.7
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                term = ((ratio ** 2) * x * np.sin(x + ratio)) % 1
                extra_sum += term * (x ** 2.2)
            score += extra_sum / 7
        elif 0.15 <= ratio <= 0.4:
            for m in range(1, 9):
                numer = (ratio ** (m + 3)) * (np.cos(m) + 1.5) * (m ** 3)
                denom = (m + 3) ** 1.1 + np.log1p(m)
                score += numer / denom
            remainder = capacity - item
            if remainder < 5:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 8 == 0:
                score *= 1.4
            if score > 18:
                score /= 3.8
        elif 0.4 < ratio <= 0.75:
            penalty_base = 0
            diff = ratio - 0.4
            for p in range(1, 14):
                power_term = (diff ** p) * np.exp(-p / 10) * (p ** 1.9)
                penalty_base += power_term
                if penalty_base > 70:
                    penalty_base = np.log1p(penalty_base) * 1.2
                    break
            score = penalty_base * 14
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 13 == 0):
                score -= 7
            if score < 0:
                score *= -1.7
                score += 8
            if score > 140:
                score = 140
        elif 0.75 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.75
            for q in range(1, 14):
                div = max(q + 0.8, 1)
                penalty_ext += ((diff) ** q) * (q ** 3.1) / div
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 2) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.3)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6 + 1
            if score > 1600:
                score = 1600
        else:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.7)
                if term > 15000:
                    term = np.sqrt(term) * np.log1p(term)
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.75 + 5
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 3:
            score *= 2.8
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q25, q50, q75 = np.percentile(finite_priorities, [25, 50, 75])
        top_count = np.sum(finite_priorities > q75)
        median_val = q50
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 1.1
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
